import React, { useState, useEffect, useRef, useMemo } from 'react';
import { motion, AnimatePresence, useScroll, useTransform } from 'framer-motion';
import { ArrowRight, LucideIcon } from 'lucide-react';
import { SectionData } from '../constants/sections';

interface SectionProps extends SectionData {
  isActive: boolean;
}

export const SectionBadge = ({ label, icon: Icon }: { label: string; icon?: LucideIcon }) => (
  <div className="flex items-center gap-4 mb-8">
    <div className="p-2 bg-primary/5 border border-primary/10 backdrop-blur-md rounded-full">
      {Icon ? <Icon size={14} className="text-primary/70" /> : <div className="w-[14px] h-[14px] flex items-center justify-center"><div className="w-1.5 h-1.5 rounded-full bg-primary/50" /></div>}
    </div>
    <span className="font-mono text-[9px] tracking-[0.4em] text-primary/60 uppercase font-bold">
      {label}
    </span>
  </div>
);

const TechBackgroundLayer: React.FC = () => {
  const elements = useMemo(() => Array.from({ length: 12 }).map((_, i) => ({
    id: i,
    x: Math.random() * 100,
    y: Math.random() * 100,
    duration: Math.random() * 15 + 10,
    char: ['0', '1', '<', '>', '{', '}', '/', '#'][Math.floor(Math.random() * 8)]
  })), []);

  return (
    <div className="absolute inset-0 z-[2] overflow-hidden pointer-events-none opacity-20">
      {elements.map((el) => (
        <motion.div
          key={el.id}
          initial={{ opacity: 0, x: `${el.x}%`, y: `${el.y}%` }}
          animate={{
            opacity: [0, 0.3, 0],
            y: [`${el.y}%`, `${el.y - 10}%`],
          }}
          transition={{
            duration: el.duration,
            repeat: Infinity,
            ease: "linear",
            delay: el.id * 0.4
          }}
          className="absolute font-mono text-primary text-[10px] font-bold"
        >
          {el.char}
        </motion.div>
      ))}
      <motion.div
        animate={{ y: ['-10%', '110%'] }}
        transition={{ duration: 10, repeat: Infinity, ease: "linear" }}
        className="absolute left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-primary/20 to-transparent blur-[1px]"
      />
      <div className="absolute inset-0 bg-[radial-gradient(#ffffff05_1px,transparent_1px)] [background-size:30px_30px]" />
    </div>
  );
};

export const BrandingSeal = () => (
  <span className="inline-block w-[0.18em] h-[0.18em] bg-primary rounded-full ml-[0.1em] mb-[0.12em] align-baseline shadow-[0_0_10px_rgba(59,130,246,0.5)]" />
);

const Section: React.FC<SectionProps> = ({ 
  isActive, 
  subtitle, 
  title, 
  content, 
  showButton, 
  buttonText, 
  backgroundImage,
  id 
}) => {
  const [isLoaded, setIsLoaded] = useState(false);
  const sectionRef = useRef<HTMLElement>(null);
  const isHero = id === 'hero';

  const { scrollYProgress } = useScroll({
    target: sectionRef,
    offset: ["start end", "end start"]
  });

  const backgroundY = useTransform(scrollYProgress, [0, 1], ["-10%", "10%"]);

  useEffect(() => {
    if (backgroundImage) {
      const img = new Image();
      img.src = backgroundImage;
      img.onload = () => setIsLoaded(true);
    } else {
      setIsLoaded(true);
    }
  }, [backgroundImage]);

  return (
    <section 
      id={id} 
      ref={sectionRef}
      className="relative h-[100dvh] w-full snap-child flex flex-col justify-center overflow-hidden bg-surface"
      style={{ scrollSnapAlign: 'start', scrollSnapStop: 'always' }}
    >
      <div className="absolute inset-0 z-0 overflow-hidden">
        <AnimatePresence mode="wait">
          {backgroundImage && isLoaded && (
            <motion.div 
              key={backgroundImage}
              initial={{ opacity: 0, scale: 1.1 }}
              animate={isActive ? { 
                opacity: isHero ? 0.3 : 0.15, 
                scale: 1 
              } : { opacity: 0, scale: 1.1 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 1.5, ease: [0.22, 1, 0.36, 1] }}
              className="absolute inset-0 z-0 bg-cover bg-center grayscale-[0.3]"
              style={{ 
                y: backgroundY, 
                backgroundImage: `url(${backgroundImage})` 
              }}
            />
          )}
        </AnimatePresence>

        {isHero && <TechBackgroundLayer />}

        <div className="absolute inset-0 z-[3] pointer-events-none">
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-b from-surface via-transparent to-surface opacity-70" />
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-r from-surface via-surface/30 to-transparent" />
        </div>
      </div>

      <div className="relative z-10 px-6 md:px-20 lg:px-32 max-w-7xl w-full mx-auto">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={isActive ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
          transition={{ duration: 0.8, ease: [0.22, 1, 0.36, 1] }}
        >
          {subtitle && <div className="mb-2">{subtitle}</div>}

          <h1 className="text-3xl md:text-5xl lg:text-6xl xl:text-7xl font-heading font-extrabold tracking-[-0.06em] mb-6 md:mb-8 text-white leading-[0.9] flex items-baseline">
            {title}<BrandingSeal />
          </h1>

          {content && (
            <p className="text-sm md:text-lg lg:text-xl text-white/50 max-w-2xl leading-[1.6] mb-8 md:mb-12 font-medium tracking-tight">
              {content}
            </p>
          )}

          {showButton && (
            <motion.button 
              whileHover={{ scale: 1.02, x: 5 }}
              whileTap={{ scale: 0.98 }}
              className="group bg-primary text-white font-bold py-2.5 px-6 md:py-6 md:px-16 rounded-xl flex items-center justify-center gap-4 transition-all shadow-xl shadow-primary/20 w-fit"
            >
              <span className="text-[9px] md:text-[11px] uppercase tracking-[0.3em] font-black">{buttonText}</span>
              <ArrowRight size={18} className="group-hover:translate-x-1.5 transition-transform" />
            </motion.button>
          )}
        </motion.div>
      </div>

      {isHero && (
        <motion.div 
          initial={{ opacity: 0 }}
          animate={isActive ? { opacity: 0.6 } : {}}
          className="absolute bottom-8 left-6 md:left-20 lg:left-32 flex flex-col items-center gap-3 transition-opacity duration-700"
        >
          <span className="font-mono text-[7px] tracking-[0.5em] uppercase font-black text-white/60">SCROLL</span>
          <div className="w-[1px] h-10 bg-white/20 relative overflow-hidden">
            <motion.div 
              animate={{ y: ['-100%', '100%'] }}
              transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
              className="absolute top-0 left-0 w-full h-1/2 bg-primary"
            />
          </div>
        </motion.div>
      )}
    </section>
  );
};

export default Section;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence, useScroll, useTransform } from 'framer-motion';
import { Mail, Phone, MapPin, Terminal, Shield, ArrowRight } from 'lucide-react';
import type { Language } from '../constants/sections';
import { BrandingSeal, SectionBadge } from './Section';

interface ContactSectionProps {
  isActive: boolean;
  language: Language;
}

const contactData = {
  mk: {
    title: "Контакт",
    subtitle: "Подготвени сте за следното поглавје? Тука сме за вашите идеи.",
    button: "Испрати порака",
    info: { address: "Гостивар, Македонија", phone: "+38970123456", email: "hello@mmmedia.mk" },
    copyright: "© 2016 M&M MEDIA"
  },
  en: {
    title: "Contact",
    subtitle: "Ready for the next chapter? We are here for your ideas.",
    button: "Send Message",
    info: { address: "Gostivar, Macedonia", phone: "+38970123456", email: "hello@mmmedia.mk" },
    copyright: "© 2016 M&M MEDIA"
  }
};

const ContactSection: React.FC<ContactSectionProps> = ({ isActive, language }) => {
  const data = contactData[language];
  const sectionRef = useRef<HTMLElement>(null);
  const [isLoaded, setIsLoaded] = useState(false);
  const backgroundImage = 'https://images.unsplash.com/photo-1550751827-4bd374c3f58b?auto=format&fit=crop&w=1920&q=80';

  const { scrollYProgress } = useScroll({
    target: sectionRef,
    offset: ["start end", "end start"]
  });

  const backgroundY = useTransform(scrollYProgress, [0, 1], ["-10%", "10%"]);

  useEffect(() => {
    const img = new Image();
    img.src = backgroundImage;
    img.onload = () => setIsLoaded(true);
  }, []);

  return (
    <section 
      id="contact" 
      ref={sectionRef}
      className="relative h-[100dvh] w-full snap-child flex flex-col justify-between overflow-hidden bg-surface"
    >
      <div className="absolute inset-0 z-0 overflow-hidden">
        <AnimatePresence mode="wait">
          {isLoaded && (
            <motion.div 
              initial={{ opacity: 0, scale: 1.1 }}
              animate={isActive ? { opacity: 0.15, scale: 1 } : { opacity: 0, scale: 1.1 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 1.5, ease: [0.22, 1, 0.36, 1] }}
              className="absolute inset-0 z-0 bg-cover bg-center grayscale-[0.5]"
              style={{ 
                y: backgroundY, 
                backgroundImage: `url(${backgroundImage})` 
              }}
            />
          )}
        </AnimatePresence>

        <div className="absolute inset-0 z-[3] pointer-events-none">
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-b from-surface via-transparent to-surface opacity-80" />
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-r from-surface via-surface/50 to-transparent" />
        </div>
      </div>

      <div className="relative z-10 px-6 md:px-20 lg:px-32 flex-1 flex flex-col justify-center max-w-7xl w-full">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={isActive ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
          transition={{ duration: 0.8, ease: [0.22, 1, 0.36, 1] }}
        >
          <div className="hidden md:block">
            <SectionBadge label="SECURE_LINK" icon={Terminal} />
          </div>

          <h2 className="text-3xl md:text-5xl lg:text-6xl xl:text-7xl font-heading font-extrabold tracking-[-0.07em] mb-4 md:mb-8 text-white leading-[0.85] flex items-baseline">
            {data.title}<BrandingSeal />
          </h2>

          <p className="text-sm md:text-lg lg:text-xl text-white/40 max-w-2xl leading-[1.6] mb-6 md:mb-12 font-medium tracking-tight">
            {data.subtitle}
          </p>

          <motion.button 
            whileHover={{ scale: 1.02, x: 5 }}
            whileTap={{ scale: 0.98 }}
            className="group bg-primary text-white font-bold py-2.5 px-6 md:py-6 md:px-16 rounded-xl flex items-center justify-center gap-4 transition-all shadow-xl shadow-primary/20 w-fit"
          >
            <span className="text-[9px] md:text-[11px] uppercase tracking-[0.3em] font-black">{data.button}</span>
            <ArrowRight size={18} className="group-hover:translate-x-1.5 transition-transform" />
          </motion.button>
        </motion.div>
      </div>

      <div className="relative z-10 px-4 md:px-20 lg:px-32 pb-4 md:pb-12 w-full max-w-7xl mx-auto">
        <div className="border-t border-white/5 pt-4 md:pt-12">
          <div className="grid grid-cols-3 gap-x-2 md:gap-12 w-full mb-6 md:mb-8">
            <ContactInfo label="MAIL" value={data.info.email} icon={Mail} />
            <ContactInfo label="SIGNAL" value={data.info.phone} icon={Phone} />
            <ContactInfo label="GEO" value={data.info.address} icon={MapPin} />
          </div>

          <div className="flex flex-col items-center md:items-end justify-center pt-2 md:pt-0 opacity-50 w-full transition-opacity duration-500">
            <div className="flex items-center gap-1.5 mb-1">
              <Shield size={7} className="text-primary md:w-[10px] md:h-[10px]" />
              <span className="font-mono text-[5px] md:text-[8px] tracking-widest uppercase font-black text-white/80">Secure</span>
            </div>
            <div className="font-mono text-[7px] md:text-[9px] text-white/60 uppercase tracking-[0.3em] font-bold text-center md:text-right">
              {data.copyright}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

const ContactInfo: React.FC<{ label: string; value: string; icon: any }> = ({ label, value, icon: Icon }) => (
  <div className="flex flex-col items-center md:items-start group cursor-pointer w-full overflow-hidden">
    <span className="text-[5px] md:text-[8px] font-mono font-black text-primary/40 uppercase tracking-[0.1em] md:tracking-[0.4em] mb-1.5">{label}</span>
    <div className="flex items-center gap-1 md:gap-4 text-white/30 group-hover:text-white/80 transition-all duration-300">
      <div className="p-1 md:p-2 rounded-full bg-white/5 border border-white/5 group-hover:border-primary/30 transition-all flex-shrink-0">
        <Icon size={9} className="text-primary/40 group-hover:text-primary transition-all md:w-[14px] md:h-[14px]" />
      </div>
      <span className="text-[7px] md:text-[13px] font-bold font-mono tracking-tighter md:tracking-tight uppercase truncate max-w-full">
        {value}
      </span>
    </div>
  </div>
);

export default ContactSection;
